    let raw_value = line[eq_pos+1..].trim();
    // Strip inline comments (# or ;)
    let value = raw_value
        .find(|c| c == '#' || c == ';')
        .map(|pos| &raw_value[..pos])
        .unwrap_or(raw_value)
        .trim()
        .to_string();
